:root {
  --bg-card: #0f0f1a;
  --bg-header: #1a1a2e;
  --bg-tabs: #12121f;
  --bg-item: #1e1e32;
  --bg-item-headliner: #22203a;
  --bg-footer: #16162a;
  --accent-primary: #c084fc;
  --accent-secondary: #38bdf8;
  --accent-hot: #fb923c;
  --accent-new: #34d399;
  --text-primary: #f0f0ff;
  --text-secondary: #9898b8;
  --text-muted: #5a5a7a;
  --tab-active-bg: #c084fc;
  --tab-active-text: #0f0f1a;
  --headliner-border: #c084fc;
  --badge-headliner-bg: #3b1f5e;
  --badge-headliner-text: #c084fc;
  --badge-hot-bg: #431a07;
  --badge-hot-text: #fb923c;
  --badge-new-bg: #063a25;
  --badge-new-text: #34d399;
  --divider: #2a2a44;
  --cta-bg: #c084fc;
  --cta-text: #0f0f1a;
  --logo-icon-color: #c084fc;
}

.festival-card {
  width: 500px;
  background: var(--bg-card);
  border-radius: 16px;
  overflow: hidden;
  border: 1px solid var(--divider);
}

.festival-header {
  background: var(--bg-header);
  padding: 14px 18px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  border-bottom: 1px solid var(--divider);
}

.festival-logo {
  display: flex;
  align-items: center;
  gap: 10px;
}

.logo-icon {
  font-size: 28px;
  color: var(--logo-icon-color);
  line-height: 1;
}

.logo-text {
  display: flex;
  flex-direction: column;
}

.festival-name {
  font-size: 16px;
  font-weight: 800;
  color: var(--text-primary);
  letter-spacing: 2px;
}

.festival-subtitle {
  font-size: 11px;
  color: var(--text-secondary);
  letter-spacing: 1px;
}

.festival-date {
  display: flex;
  flex-direction: column;
  align-items: center;
  background: var(--accent-primary);
  color: var(--tab-active-text);
  border-radius: 8px;
  padding: 4px 10px;
}

.date-day {
  font-size: 20px;
  font-weight: 800;
  line-height: 1;
}

.date-month {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1px;
}

.stage-tabs {
  background: var(--bg-tabs);
  display: flex;
  gap: 6px;
  padding: 8px 18px;
  border-bottom: 1px solid var(--divider);
}

.tab {
  font-size: 11px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 20px;
  color: var(--text-secondary);
  cursor: pointer;
  letter-spacing: 0.5px;
}

.tab--active {
  background: var(--tab-active-bg);
  color: var(--tab-active-text);
}

.lineup-list {
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding: 8px 12px;
}

.lineup-item {
  display: flex;
  align-items: center;
  gap: 12px;
  background: var(--bg-item);
  border-radius: 8px;
  padding: 10px 12px;
  border-left: 3px solid transparent;
}

.lineup-item--headliner {
  background: var(--bg-item-headliner);
  border-left: 3px solid var(--headliner-border);
}

.lineup-time {
  font-size: 13px;
  font-weight: 700;
  color: var(--accent-secondary);
  min-width: 40px;
}

.lineup-info {
  display: flex;
  flex-direction: column;
  flex: 1;
}

.lineup-artist {
  font-size: 14px;
  font-weight: 700;
  color: var(--text-primary);
}

.lineup-genre {
  font-size: 11px;
  color: var(--text-muted);
}

.lineup-badge {
  font-size: 10px;
  font-weight: 800;
  padding: 3px 7px;
  border-radius: 4px;
  letter-spacing: 0.5px;
}

.badge--headliner {
  background: var(--badge-headliner-bg);
  color: var(--badge-headliner-text);
}

.badge--hot {
  background: var(--badge-hot-bg);
  color: var(--badge-hot-text);
}

.badge--new {
  background: var(--badge-new-bg);
  color: var(--badge-new-text);
}

.festival-footer {
  background: var(--bg-footer);
  padding: 10px 18px;
  display: flex;
  align-items: center;
  gap: 12px;
  border-top: 1px solid var(--divider);
}

.footer-stat {
  display: flex;
  flex-direction: column;
  align-items: center;
}

.stat-value {
  font-size: 16px;
  font-weight: 800;
  color: var(--text-primary);
}

.stat-label {
  font-size: 10px;
  color: var(--text-muted);
  letter-spacing: 0.5px;
}

.footer-divider {
  width: 1px;
  height: 28px;
  background: var(--divider);
}

.footer-cta {
  margin-left: auto;
  background: var(--cta-bg);
  color: var(--cta-text);
  font-size: 12px;
  font-weight: 800;
  padding: 8px 16px;
  border-radius: 8px;
  letter-spacing: 1px;
}
